def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        magnitude = 0.0
        complexity = 0.0
        factor = 1.0
        for j in range(1, 20):
            if j % 2 == 0:
                factor *= 1.03 + 0.007 * j
            elif j % 4 == 1:
                factor *= 0.97 - 0.004 * j
            if ratio < 0.05 * j:
                magnitude += np.tanh(ratio * j) * (j**1.5) * factor
            else:
                magnitude += np.cosh(0.1 * j) / (j + 1) * factor
            if (cap * j + item) % 9 == 0:
                magnitude *= 1.06
            elif (cap + item * j) % 11 == 0:
                magnitude *= 0.94
            if j == 10:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            complexity += np.log1p(diff) / (k + 4)
                        else:
                            complexity -= np.exp(-diff/(k+5))
                    else:
                        complexity -= abs(diff)**1.7 / (k + 6)
            if ratio > 0.9 and j % 5 == 0:
                factor *= 1.08 + 0.015 * j
            elif ratio < 0.1 and j % 6 == 0:
                factor *= 0.88 - 0.012 * j
            if j % 7 == 3 and cap % (j+2) == 0:
                complexity += np.cos(j*ratio) * 0.7
            if j % 3 == 2 and (cap + j*j) % 5 == 0:
                factor *= 1.02
        score = magnitude + complexity * 0.9
        score *= factor
        if score < 0:
            priorities[i] = -score * (np.log1p(cap) + np.sqrt(item))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 2) * (1 + ratio * 1.2)
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**1.5)
            else:
                priorities[i] = -score / (cap + item + 1)
        if ratio > 0.97:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        if int(np.floor(cap)) % 2 == 0 and int(np.floor(item)) % 2 == 1:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 0.99
        if priorities[i] > 1e6:
            priorities[i] = 1e6
        elif priorities[i] < -1e6:
            priorities[i] = -1e6
    return priorities
